INSERT INTO `faq` VALUES (15,'Jak zainstalować aplikację na telefonie?','<p>Możesz użyć funkcji w Google Chrome - <span style=\"color: var(--text);\">zainstaluj aplikację internetową</span>, lub dodać <span style=\"color: var(--text);\">skrót </span>do ekranu startowego telefonu na innych przeglądarkach.</p>'),(16,'Jak zainstalować aplikację na PC?','<p>Niestety nie ma takiej możliwości, możesz<span style=\"color: var(--text);\"> przypiąć link </span>w zakładkach, aby wracać do nas.</p>'),(17,'Czy HomeList jest darmowe?','<p><span style=\"color: var(--text);\">Tak!</span></p><p>Nasza aplikacja jest<span style=\"color: var(--text);\"> darmowa</span> dla zwykłych użytkowników, jedyne opłaty są gdy będziesz chciał/a zainstalować aplikację lokalnie u siebie na serwerze.</p>'),(18,'Jak zintegrować z HomeAssistant?','<p>Integracja z HomeAssistant jest bardzo prosta, wystarczy adres <span style=\"color: var(--text);\">https://homelist.rgbpc.pl/panel</span> umieścić w elemencie konstrukcyjnym panelu <span style=\"color: var(--text);\">iframe</span> i działa!</p>'),(19,'Widzisz błąd na stronie?','<p>Aplikacja jest na etapie rozwoju i część funkcjonalności nie jest obecna, oraz mogą pojawiać się błędy. Jeżeli widzisz jakieś błędy napisz do nas na: gugisek@gmail.com.</p>');
/*!40000 ALTER TABLE `faq` ENABLE KEYS */;
UNLOCK TABLES;

